353: ListenerManagerImpl::ListenerManagerImpl(Instance& server,
354:                                          std::unique_ptr<ListenerComponentFactory>&& factory,
355:                                          WorkerFactory& worker_factory,
356:                                          bool enable_dispatcher_stats,
357:                                          Quic::QuicStatNames& quic_stat_names)
358:     : server_(server), factory_(std::move(factory)),
359:       scope_(server.stats().createScope("listener_manager.")), stats_(generateStats(*scope_)),
360:       enable_dispatcher_stats_(enable_dispatcher_stats), quic_stat_names_(quic_stat_names) {
361:   if (!factory_) {
362:     factory_ = std::make_unique<ProdListenerComponentFactory>(server);
363:   }
364:   if (server.admin().has_value()) {
365:     config_tracker_entry_ = server.admin()->getConfigTracker().add(
366:         "listeners", [this](const Matchers::StringMatcher& name_matcher) {
367:           return dumpListenerConfigs(name_matcher);
368:         });
369:   }
370: 
371:   for (uint32_t i = 0; i < server.options().concurrency(); i++) {
372:     workers_.emplace_back(worker_factory.createWorker(
373:         i, server.overloadManager(), server.nullOverloadManager(), absl::StrCat("worker_", i)));
374:   }
375: }
