89: ListenSocketFactoryImpl::ListenSocketFactoryImpl(
90:     ListenerComponentFactory& factory, Network::Address::InstanceConstSharedPtr address,
91:     Network::Socket::Type socket_type, const Network::Socket::OptionsSharedPtr& options,
92:     const std::string& listener_name, uint32_t tcp_backlog_size,
93:     ListenerComponentFactory::BindType bind_type,
94:     const Network::SocketCreationOptions& creation_options, uint32_t num_sockets,
95:     absl::Status& creation_status)
96:     : factory_(factory), local_address_(address), socket_type_(socket_type), options_(options),
97:       listener_name_(listener_name), tcp_backlog_size_(tcp_backlog_size), bind_type_(bind_type),
98:       socket_creation_options_(creation_options) {
99: 
100:   if (local_address_->type() == Network::Address::Type::Ip) {
101:     if (socket_type == Network::Socket::Type::Datagram) {
102:       ASSERT(bind_type_ == ListenerComponentFactory::BindType::ReusePort || num_sockets == 1u);
103:     }
104:   } else {
105:     if (local_address_->type() == Network::Address::Type::Pipe) {
106:       // Listeners with Unix domain socket always use shared socket.
107:       // TODO(mattklein123): This should be blocked at the config parsing layer instead of getting
108:       // here and disabling reuse_port.
109:       if (bind_type_ == ListenerComponentFactory::BindType::ReusePort) {
110:         bind_type_ = ListenerComponentFactory::BindType::NoReusePort;
111:       }
112:     } else {
113:       ASSERT(local_address_->type() == Network::Address::Type::EnvoyInternal);
114:       bind_type_ = ListenerComponentFactory::BindType::NoBind;
115:     }
116:   }
117: 
118:   auto socket_or_error = createListenSocketAndApplyOptions(factory, socket_type, 0);
119:   SET_AND_RETURN_IF_NOT_OK(socket_or_error.status(), creation_status);
120:   sockets_.push_back(*socket_or_error);
121: 
122:   if (sockets_[0] != nullptr && local_address_->ip() && local_address_->ip()->port() == 0) {
123:     local_address_ = sockets_[0]->connectionInfoProvider().localAddress();
124:   }
125:   ENVOY_LOG(debug, "Set listener {} socket factory local address to {}", listener_name,
126:             local_address_->asString());
127: 
128:   // Now create the remainder of the sockets that will be used by the rest of the workers.
129:   for (uint32_t i = 1; i < num_sockets; i++) {
130:     if (bind_type_ != ListenerComponentFactory::BindType::ReusePort && sockets_[0] != nullptr) {
131:       sockets_.push_back(sockets_[0]->duplicate());
132:     } else {
133:       auto socket_or_error = createListenSocketAndApplyOptions(factory, socket_type, i);
134:       SET_AND_RETURN_IF_NOT_OK(socket_or_error.status(), creation_status);
135:       sockets_.push_back(*socket_or_error);
136:     }
137:   }
138:   ASSERT(sockets_.size() == num_sockets);
139: }
