141: ListenSocketFactoryImpl::ListenSocketFactoryImpl(const ListenSocketFactoryImpl& factory_to_clone)
142:     : factory_(factory_to_clone.factory_), local_address_(factory_to_clone.local_address_),
143:       socket_type_(factory_to_clone.socket_type_), options_(factory_to_clone.options_),
144:       listener_name_(factory_to_clone.listener_name_),
145:       tcp_backlog_size_(factory_to_clone.tcp_backlog_size_),
146:       bind_type_(factory_to_clone.bind_type_),
147:       socket_creation_options_(factory_to_clone.socket_creation_options_) {
148:   for (auto& socket : factory_to_clone.sockets_) {
149:     // In the cloning case we always duplicate() the socket. This makes sure that during listener
150:     // update/drain we don't lose any incoming connections when using reuse_port. Specifically on
151:     // Linux the use of SO_REUSEPORT causes the kernel to allocate a separate queue for each socket
152:     // on the same address. Incoming connections are immediately assigned to one of these queues.
153:     // If connections are in the queue when the socket is closed, they are closed/reset, not sent to
154:     // another queue. So avoid making extra queues in the kernel, even temporarily.
155:     //
156:     // TODO(mattklein123): In the current code as long as the address matches, the socket factory
157:     // will be cloned, effectively ignoring any changed socket options. The code should probably
158:     // block any updates to listeners that use the same address but different socket options.
159:     // (It's possible we could handle changing some socket options, but this would be tricky and
160:     // probably not worth the difficulty.)
161:     sockets_.push_back(socket->duplicate());
162:   }
163: }
