165: absl::StatusOr<Network::SocketSharedPtr> ListenSocketFactoryImpl::createListenSocketAndApplyOptions(
166:     ListenerComponentFactory& factory, Network::Socket::Type socket_type, uint32_t worker_index) {
167:   // Socket might be nullptr when doing server validation.
168:   // TODO(mattklein123): See the comment in the validation code. Make that code not return nullptr
169:   // so this code can be simpler.
170:   absl::StatusOr<Network::SocketSharedPtr> socket_or_error = factory.createListenSocket(
171:       local_address_, socket_type, options_, bind_type_, socket_creation_options_, worker_index);
172:   RETURN_IF_NOT_OK_REF(socket_or_error.status());
173:   Network::SocketSharedPtr socket = std::move(*socket_or_error);
174: 
175:   // Binding is done by now.
176:   ENVOY_LOG(debug, "Create listen socket for listener {} on address {}", listener_name_,
177:             local_address_->asString());
178:   if (socket != nullptr && options_ != nullptr) {
179:     const bool ok = Network::Socket::applyOptions(
180:         options_, *socket, envoy::config::core::v3::SocketOption::STATE_BOUND);
181:     const std::string message =
182:         fmt::format("{}: Setting socket options {}", listener_name_, ok ? "succeeded" : "failed");
183:     if (!ok) {
184:       ENVOY_LOG(warn, "{}", message);
185:       return absl::InvalidArgumentError(message);
186:     } else {
187:       ENVOY_LOG(debug, "{}", message);
188:     }
189: 
190:     // Add the options to the socket_ so that STATE_LISTENING options can be
191:     // set after listen() is called and immediately before the workers start running.
192:     socket->addOptions(options_);
193:   }
194:   return socket;
195: }
