243: std::string listenerStatsScope(const envoy::config::listener::v3::Listener& config) {
244:   if (!config.stat_prefix().empty()) {
245:     return config.stat_prefix();
246:   }
247:   if (config.has_internal_listener()) {
248:     return absl::StrCat("envoy_internal_", config.name());
249:   }
