284: ListenerImpl::ListenerImpl(const envoy::config::listener::v3::Listener& config,
285:                            const std::string& version_info, ListenerManagerImpl& parent,
286:                            const std::string& name, bool added_via_api, bool workers_started,
287:                            uint64_t hash, absl::Status& creation_status)
288:     : parent_(parent),
289:       socket_type_(config.has_internal_listener()
290:                        ? Network::Socket::Type::Stream
291:                        : Network::Utility::protobufAddressSocketType(config.address())),
292:       bind_to_port_(shouldBindToPort(config)), mptcp_enabled_(config.enable_mptcp()),
293:       hand_off_restored_destination_connections_(
294:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, use_original_dst, false)),
295:       per_connection_buffer_limit_bytes_(
296:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, per_connection_buffer_limit_bytes, 1024 * 1024)),
297:       listener_tag_(parent_.factory_->nextListenerTag()), name_(name),
298:       added_via_api_(added_via_api), workers_started_(workers_started), hash_(hash),
299:       tcp_backlog_size_(
300:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, tcp_backlog_size, ENVOY_TCP_BACKLOG_SIZE)),
301:       max_connections_to_accept_per_socket_event_(
302:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, max_connections_to_accept_per_socket_event,
303:                                           Network::DefaultMaxConnectionsToAcceptPerSocketEvent)),
304:       validation_visitor_(
305:           added_via_api_ ? parent_.server_.messageValidationContext().dynamicValidationVisitor()
306:                          : parent_.server_.messageValidationContext().staticValidationVisitor()),
307:       ignore_global_conn_limit_(config.ignore_global_conn_limit()),
308:       bypass_overload_manager_(config.bypass_overload_manager()),
309:       listener_init_target_(fmt::format("Listener-init-target {}", name),
310:                             [this]() { dynamic_init_manager_->initialize(local_init_watcher_); }),
311:       dynamic_init_manager_(std::make_unique<Init::ManagerImpl>(
312:           fmt::format("Listener-local-init-manager {} {}", name, hash))),
313:       config_(config), version_info_(version_info),
314:       listener_filters_timeout_(
315:           PROTOBUF_GET_MS_OR_DEFAULT(config, listener_filters_timeout, 15000)),
316:       continue_on_listener_filters_timeout_(config.continue_on_listener_filters_timeout()),
317:       listener_factory_context_(std::make_shared<PerListenerFactoryContextImpl>(
318:           parent.server_, validation_visitor_, config, *this,
319:           parent_.factory_->createDrainManager(config.drain_type()))),
320:       reuse_port_(getReusePortOrDefault(parent_.server_, config, socket_type_)),
321:       cx_limit_runtime_key_("envoy.resource_limits.listener." + config.name() +
322:                             ".connection_limit"),
323:       open_connections_(std::make_shared<BasicResourceLimitImpl>(
324:           std::numeric_limits<uint64_t>::max(),
325:           listener_factory_context_->serverFactoryContext().runtime(), cx_limit_runtime_key_)),
326:       local_init_watcher_(fmt::format("Listener-local-init-watcher {}", name),
327:                           [this] {
328:                             if (workers_started_) {
329:                               parent_.onListenerWarmed(*this);
330:                             } else {
331:                               // Notify Server that this listener is
332:                               // ready.
333:                               listener_init_target_.ready();
334:                             }
335:                           }),
336:       transport_factory_context_(
337:           std::make_shared<Server::Configuration::TransportSocketFactoryContextImpl>(
338:               parent_.server_.serverFactoryContext(), parent_.server_.sslContextManager(),
339:               listenerScope(), parent_.server_.clusterManager(), validation_visitor_)),
340:       quic_stat_names_(parent_.quicStatNames()),
341:       missing_listener_config_stats_({ALL_MISSING_LISTENER_CONFIG_STATS(
342:           POOL_COUNTER(listener_factory_context_->listenerScope()))}) {
343:   std::vector<std::reference_wrapper<
344:       const Protobuf::RepeatedPtrField<envoy::config::core::v3::SocketOption>>>
345:       address_opts_list;
346:   if (config.has_internal_listener()) {
347:     addresses_.emplace_back(
348:         std::make_shared<Network::Address::EnvoyInternalInstance>(config.name()));
349:     address_opts_list.emplace_back(std::ref(config.socket_options()));
350:   } else {
351:     // All the addresses should be same socket type, so get the first address's socket type is
352:     // enough.
353:     auto address_or_error = Network::Address::resolveProtoAddress(config.address());
354:     SET_AND_RETURN_IF_NOT_OK(address_or_error.status(), creation_status);
355:     auto address = std::move(address_or_error.value());
356:     SET_AND_RETURN_IF_NOT_OK(checkIpv4CompatAddress(address, config.address()), creation_status);
357:     addresses_.emplace_back(address);
358:     address_opts_list.emplace_back(std::ref(config.socket_options()));
359: 
360:     for (auto i = 0; i < config.additional_addresses_size(); i++) {
361:       if (socket_type_ !=
362:           Network::Utility::protobufAddressSocketType(config.additional_addresses(i).address())) {
363:         creation_status = absl::InvalidArgumentError(
364:             fmt::format("listener {}: has different socket type. The listener only "
365:                         "support same socket type for all the addresses.",
366:                         name_));
367:         return;
368:       }
369:       auto addresses_or_error =
370:           Network::Address::resolveProtoAddress(config.additional_addresses(i).address());
371:       SET_AND_RETURN_IF_NOT_OK(addresses_or_error.status(), creation_status);
372:       auto additional_address = std::move(addresses_or_error.value());
373:       SET_AND_RETURN_IF_NOT_OK(
374:           checkIpv4CompatAddress(address, config.additional_addresses(i).address()),
375:           creation_status);
376:       addresses_.emplace_back(additional_address);
377:       if (config.additional_addresses(i).has_socket_options()) {
378:         address_opts_list.emplace_back(
379:             std::ref(config.additional_addresses(i).socket_options().socket_options()));
380:       } else {
381:         address_opts_list.emplace_back(std::ref(config.socket_options()));
382:       }
383:     }
384:   }
385: 
386:   const absl::optional<std::string> runtime_val =
387:       listener_factory_context_->serverFactoryContext().runtime().snapshot().get(
388:           cx_limit_runtime_key_);
389:   if (runtime_val && runtime_val->empty()) {
390:     ENVOY_LOG(warn,
391:               "Listener connection limit runtime key {} is empty. There are currently no "
392:               "limitations on the number of accepted connections for listener {}.",
393:               cx_limit_runtime_key_, config.name());
394:   }
395: 
396:   filter_chain_manager_ = std::make_unique<FilterChainManagerImpl>(
397:       addresses_, listener_factory_context_->parentFactoryContext(), initManager()),
398: 
399:   buildAccessLog(config);
400:   SET_AND_RETURN_IF_NOT_OK(validateConfig(), creation_status);
401: 
402:   // buildUdpListenerFactory() must come before buildListenSocketOptions() because the UDP
403:   // listener factory can provide additional options.
404:   SET_AND_RETURN_IF_NOT_OK(buildUdpListenerFactory(config, parent_.server_.options().concurrency()),
405:                            creation_status);
406:   buildListenSocketOptions(config, address_opts_list);
407:   SET_AND_RETURN_IF_NOT_OK(createListenerFilterFactories(config), creation_status);
408:   SET_AND_RETURN_IF_NOT_OK(validateFilterChains(config), creation_status);
409:   SET_AND_RETURN_IF_NOT_OK(buildFilterChains(config), creation_status);
410:   if (socket_type_ != Network::Socket::Type::Datagram) {
411:     buildSocketOptions(config);
412:     buildOriginalDstListenerFilter(config);
413:     buildProxyProtocolListenerFilter(config);
414:     SET_AND_RETURN_IF_NOT_OK(buildInternalListener(config), creation_status);
415:   }
416:   if (!workers_started_) {
417:     // Initialize dynamic_init_manager_ from Server's init manager if it's not initialized.
418:     // NOTE: listener_init_target_ should be added to parent's initManager at the end of the
419:     // listener constructor so that this listener's children entities could register their targets
420:     // with their parent's initManager.
421:     parent_.server_.initManager().add(listener_init_target_);
422:   }
423: }
